  "group": "Retrieval",
  "options": [
    {
      "text": "मॉडल प्रदर्शन संदर्भ की स्थिति से निरपेक्ष रूप से समान रहता है"
    },
    {
      "text": "मॉडल संदर्भ के अंत में होने पर सर्वोत्तम प्रदर्शन करते हैं"
    },
    {
      "text": "मॉडल संदर्भ के शुरूआत और अंत में होने पर सर्वोत्तम प्रदर्शन करते हैं, मध्य में सबसे कम"
    },
    {
      "text": "मॉडल संदर्भ के मध्य में होने पर सर्वोत्तम प्रदर्शन करते हैं"
    }
  ],
  "questionProse": [
    "“मध्य में खो जाना” समस्या पर शोध दिखाता है कि LLMs अक्सर:"
  ],
  "explanationProse": [
    "मध्य में खो जाना (Liu et al., 2023) पेपर ने दिखाया कि LLMs लंबे संदर्भों में मध्य में रखी जाने वाली जानकारी के साथ नियमित रूप से संघर्ष करते हैं। प्रदर्शन तब काफी अधिक होता है जब प्रासंगिक जानकारी संदर्भ खिड़की के **शुरूआत या अंत** में आती है।\n\n    व्यावहारिक अनुप्रयोग: RAG प्रॉम्प्ट में रिट्राइव किए गए चंक्स को अपने रिवर्स ऑर्डर में जोड़ने के बजाय, अपने सर्वोच्च-रैंकित परिणाम को पहले रखें, दूसरा-सर्वोच्च अंत में, और मध्य को कम-रैंकित सामग्री से भर दें। अंतर्दृष्टि विरोधी हो सकता है, लेकिन मापनी में बेहतर है।"
  ]
